// // This synchronous flip-flop captures the scan data (sd) instead of the normal data (d) when SE is high.
module bw_u1_syncff_4x (q, so, ck, d, se, sd);
output q, so;
input  ck, d, se, sd;
reg    q_r;
  always @ (posedge ck)
      q_r <= se ? sd : d;
  assign q  = q_r;
  assign so = q_r;
endmodule
